using namespace std;
int main(){
    int n;
    cin >> n;
    string s;
    cin >> s;
    int sign = 1;
    long long num = 0;
    int start = 0;
    while (start < s.size() && s[start] == ' ') start++;
    if (start < s.size() && (s[start] == '-' || s[start] == '+')) {
        if (s[start] == '-') sign = -1;
        start++;
    }
    for (int i = start; i < s.size(); i++) {
        if (isdigit(s[i])) {
            num = num * 10 + (s[i] - '0');
        } else {
            break;
        }
    }
    num *= sign;
    num = max(min(num, (long long)2147483647), (long long)-2147483648);
    cout << (int)num << endl;
    return 0;
}
